// ── Study Guide Definitions ──────────────────────────────────

interface GuideDef {
  subjectName: string
  topicName: string
  title: string
  content: string
}

const STUDY_GUIDES: GuideDef[] = []

// Generate 3 study guides per subject (first, middle, last topic)
for (const subj of SUBJECTS) {
  const topics = subj.topics
  const guideTopics = [topics[0], topics[Math.floor(topics.length / 2)], topics[topics.length - 1]]
  for (const topic of guideTopics) {
    STUDY_GUIDES.push({
      subjectName: subj.name,
      topicName: topic,
      title: `Study Guide: ${subj.name} - ${topic}`,
      content: generateStudyGuide(subj.name, topic, subj.topics),
    })
  }
}

function generateStudyGuide(subjectName: string, topicName: string, allTopics: string[]): string {
  return `# ${topicName}

## Key Concepts and Definitions

- **${topicName}** is a core topic within CSEC ${subjectName} that covers essential knowledge and skills for the examination
- Students are expected to demonstrate understanding of fundamental principles and their applications
- This topic typically accounts for a significant portion of the ${subjectName} examination paper
- Questions may appear in both the multiple-choice and structured/essay sections of the exam

## Important Concepts

- Focus on understanding the key definitions, principles, and theories outlined in the CSEC syllabus for ${topicName}
- Be able to explain concepts using appropriate terminology and examples
- Connect theoretical knowledge to real-world applications and Caribbean contexts
- Practice applying concepts to problem-solving scenarios

## Key Skills to Develop

1. **Recall and understanding** — Know definitions and core principles
2. **Application** — Apply knowledge to new situations and scenarios
3. **Analysis** — Break down complex problems into manageable parts
4. **Evaluation** — Make informed judgments based on evidence
5. **Communication** — Express ideas clearly and precisely

## CXC Exam Tips

- Read all questions carefully before answering — identify exactly what is being asked
- Use correct terminology throughout your answers
- Show all working and steps in calculations where applicable
- Support arguments with specific examples, especially from Caribbean contexts
- Manage your time — allocate appropriate time per question based on marks
- Review past CSEC papers to understand question patterns and expectations
- Practice under timed conditions to build exam confidence and speed

## Related Topics in ${subjectName}

This topic connects to: ${allTopics.join(', ')} — understanding these connections strengthens overall exam performance.`
}

// ── Main Seeding Function ────────────────────────────────────

async function main() {
  console.log('🌱 Seeding 16 new CSEC subjects into the database...\n')

  let subjectCount = 0
  let topicCount = 0
  let questionCount = 0
  let guideCount = 0

  // 1. Create subjects and topics
  for (const subj of SUBJECTS) {
    const subject = await db.subject.upsert({
      where: { code: subj.code },
      update: { name: subj.name, description: subj.description, color: subj.color, icon: subj.icon },
      create: { name: subj.name, code: subj.code, description: subj.description, color: subj.color, icon: subj.icon },
    })
    subjectCount++
    console.log(`  ✓ Subject: ${subj.name} (${subj.code})`)

    for (let i = 0; i < subj.topics.length; i++) {
      const topic = await db.topic.upsert({
        where: { name_subjectId: { name: subj.topics[i], subjectId: subject.id } },
        update: { order: i },
        create: { name: subj.topics[i], subjectId: subject.id, order: i },
      })
      topicCount++
    }
  }

  console.log(`\n📊 Created ${subjectCount} subjects and ${topicCount} topics.\n`)

  // 2. Create questions
  for (const [subjectCode, questions] of Object.entries(QUESTIONS)) {
    const subject = await db.subject.findUnique({ where: { code: subjectCode } })
    if (!subject) {
      console.error(`  ✗ Subject not found: ${subjectCode}`)
      continue
    }

    for (const q of questions) {
      const topic = await db.topic.findFirst({
        where: { name: q.topicName, subjectId: subject.id },
      })
      await db.question.create({
        data: {
          type: q.type,
          difficulty: q.difficulty,
          content: q.content,
          options: q.options,
          correctAnswer: q.correctAnswer,
          explanation: q.explanation,
          subjectId: subject.id,
          topicId: topic?.id || null,
          source: q.source,
        },
      })
      questionCount++
    }
    console.log(`  ✓ Questions for ${subject.name}: ${questions.length}`)
  }

  console.log(`\n📊 Created ${questionCount} questions.\n`)

  // 3. Create study guides (as Notes, same pattern as seed-study-guides.ts)
  const SYSTEM_EMAIL = 'system@cxcace.com'
  const passwordHash = await bcrypt.hash('system123', 10)

  const systemUser = await db.user.upsert({
    where: { email: SYSTEM_EMAIL },
    update: {},
    create: {
      email: SYSTEM_EMAIL,
      passwordHash,
      name: 'CXC Ace Study Guides',
      role: 'TEACHER',
      bio: 'System account that provides study guide content for all CXC and CAPE subjects.',
    },
  })

  const subjects = await db.subject.findMany()
  const subjectMap = new Map(subjects.map(s => [s.name, s]))

  for (const guide of STUDY_GUIDES) {
    const subject = subjectMap.get(guide.subjectName)
    if (!subject) continue

    try {
      await db.note.upsert({
        where: {
          id: `sg-${subject.code}-${guide.topicName.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}`,
        },
        update: {
          title: guide.title,
          content: guide.content,
          isShared: true,
          isPinned: true,
        },
        create: {
          id: `sg-${subject.code}-${guide.topicName.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}`,
          title: guide.title,
          content: guide.content,
          subjectId: subject.id,
          userId: systemUser.id,
          isShared: true,
          isPinned: true,
          color: subject.color,
        },
      })
      guideCount++
    } catch (e: any) {
      console.error(`  ✗ Error creating guide for ${guide.title}: ${e.message}`)
    }
  }

  console.log(`\n📊 Created ${guideCount} study guides.\n`)

  console.log(`${'═'.repeat(50)}`)
  console.log(`✅ CSEC seed complete!`)
  console.log(`   Subjects: ${subjectCount}`)
  console.log(`   Topics: ${topicCount}`)
  console.log(`   Questions: ${questionCount}`)
  console.log(`   Study Guides: ${guideCount}`)
  console.log(`${'═'.repeat(50)}`)

  await db.$disconnect()
}

main().catch((e) => {
  console.error('❌ Seed failed:', e)
  process.exit(1)
})
